                renderAndCreate(i)
              }
            }
          }, 150)
        })
      } catch (err) {
        if (!aborted) {
          onErrorRef.current?.(
            err instanceof Error ? err.message : "Failed to render PDF."
          )
        }
      }
    }

    init()

    return () => {
      aborted = true
      unsubscribe?.()
      for (const url of objectUrls) URL.revokeObjectURL(url)
